const intent = $json.intent || '';
const params = $json.intentParams || {};
const text = $json.inputText || '';

const intentMap = {
  'local_screenshot': { action: 'screenshot', params: {} },
  'local_browser': { action: params.action || 'browser_open', params: { url: params.url || text.match(/https?://[^\s]+/)?.[0] || 'about:blank' } },
  'local_app': { action: 'app_open', params: { app_name: params.app || text.replace(/open|launch|start/i, '').trim() } },
  'local_file': { action: params.file_action || 'file_list', params: { path: params.path || '~' } },
  'local_shell': { action: 'shell_exec', params: { command: params.command || text } },
  'local_system': { action: 'system_info', params: {} }
};

const mapped = intentMap[intent] || { action: 'system_info', params: { query: text } };

return [{
  json: {
    ...$json,
    action: mapped.action,
    params: mapped.params,
    command_id: 'cmd_' + Date.now(),
    requires_confirmation: ['shell_exec', 'file_delete', 'app_close'].includes(mapped.action)
  }
}];

const action = $json.action || 'unknown';
const params = $json.params || {};

// Fallback HTTP bridge
const http = require('http');

return new Promise((resolve) => {
  const postData = JSON.stringify({
    type: 'command',
    payload: {
      command_id: $json.command_id,
      action: action,
      params: params,
      requires_confirmation: $json.requires_confirmation
    }
  });

  const req = http.request(
    { hostname: 'localhost', port: parseInt($env.BRIDGE_PORT || '8765'), path: '/', method: 'POST', headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(postData) } },
    (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => {
        try {
          const result = JSON.parse(data);
          resolve([{ json: { ...$json, ...result, bridge_used: 'http' } }]);
        } catch (e) {
          resolve([{ json: { ...$json, responseText: data, bridge_used: 'http' } }]);
        }
      });
    }
  );
  req.on('error', () => {
    resolve([{ json: { ...$json, responseText: 'Local device bridge unavailable. Ensure bridge_server.py is running.', success: false } }]);
  });
  req.write(postData);
  req.end();
});

const res = $json;

// Check if we got a valid bridge response
if (res.status) {
  const status = res.status;
  const output = res.stdout || res.result || '';
  const error = res.stderr || res.error || '';

  if (status === 'success') {
    return [{ json: { ...$json, responseText: `✅ Command executed:

${output}`, success: true } }];
  } else if (status === 'blocked') {
    return [{ json: { ...$json, responseText: `🚫 Command blocked by safety policy.`, success: false } }];
  } else if (status === 'denied') {
    return [{ json: { ...$json, responseText: `❌ User denied the operation.`, success: false } }];
  } else if (status === 'timeout') {
    return [{ json: { ...$json, responseText: `⏰ Command timed out.`, success: false } }];
  } else {
    return [{ json: { ...$json, responseText: `⚠️ Error:
${error}
${output}`, success: false } }];
  }
}

// Direct response from HTTP fallback
return [{ json: { ...$json, responseText: res.responseText || 'Device operation completed.', success: res.success !== false } }];
